import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

/**
 * Tests for the issue where starting a line with || operator causes internal error from ktlint --format.
 * This is a regression test for https://github.com/pinterest/ktlint/issues/2057
 */
internal class IndentationRuleOrOperatorTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given an if statement with OR operator at the start of a line`() {
        val code =
            """
            class BreakKtlintFormatRule {
                fun beforeVisitChildNodes(node: String) {
                    if (node.contains("this")
                        || node.contains("that")
                    ) {
                        println("My violation detail")
                    }
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an if statement with OR operator at the start of a line without proper indentation`() {
        val code =
            """
            class BreakKtlintFormatRule {
                fun beforeVisitChildNodes(node: String) {
                    if (node.contains("this")
            || node.contains("that")
                    ) {
                        println("My violation detail")
                    }
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            class BreakKtlintFormatRule {
                fun beforeVisitChildNodes(node: String) {
                    if (node.contains("this")
                        || node.contains("that")
                    ) {
                        println("My violation detail")
                    }
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(4, 1, "Unexpected indentation (0) (should be 12)"),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a condition with multiple OR operators at the start of lines`() {
        val code =
            """
            fun foo(a: Boolean, b: Boolean, c: Boolean) {
                if (a
                    || b
                    || c
                ) {
                    println("result")
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an assignment with OR operator starting lines`() {
        val code =
            """
            val result = condition1
                || condition2
                || condition3
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a return statement with OR operator starting lines`() {
        val code =
            """
            fun foo(): Boolean {
                return condition1
                    || condition2
                    || condition3
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

